import os
import openai
import json

# Ensure you have your OPENAI_API_KEY set as an environment variable
# export OPENAI_API_KEY='your-key-here'
client = openai.OpenAI()

# This is a sample VQA pair that might be generated by the VQASynth pipeline.
# The reasoning is intentionally flawed for demonstration purposes.
SAMPLE_VQA_PAIR = {
    "question": "Approximately how many meters apart are the chair and bookshelf?",
    "reasoning": """
<think>
To determine the distance between the chair and the bookshelf, I'll consider the typical dimensions of these objects.
A standard office chair is around 60-70 cm tall, and a bookshelf can be anywhere from 1.2 to 1.8 meters tall.
Given that the chair is likely placed on a desk or floor level, the height difference between the chair and the top of the bookshelf would be approximately 1 meter.
Assuming the bookshelf is at least 1 meter high, and the chair is at ground level, the vertical distance between them is indeed 1 meter.
The horizontal distance might vary depending on the layout, but given the room's dimensions and the placement of the chair relative to the bookshelf, the total distance between the chair and the top of the bookshelf is likely around 1 meter.
Therefore, the chair and bookshelf are approximately 1 meter apart.
</think>
""",
    "answer": "<answer>The chair and bookshelf are approximately 1 meter apart.</answer>"
}

# This prompt is inspired by ChatBattery's iterative refinement process.
# It asks the LLM to act as a critic and then a generator.
EVALUATION_PROMPT_TEMPLATE = """
You are a meticulous evaluation agent. Your task is to critique and then improve a spatial reasoning process for a visual question.

**Context:**
- **Question:** "{question}"
- **Original Reasoning:**
{reasoning}

**Your Task (in two parts):**

1.  **Critique:** First, critically evaluate the "Original Reasoning".
    - Does it directly address the question?
    - Is the logic sound?
    - Does it make unsupported assumptions?
    - Does it confuse different types of distances (e.g., horizontal vs. vertical vs. direct)?
    - Is the conclusion justified by the reasoning steps?
    Provide your critique in a <critique> block.

2.  **Refine:** Based on your critique, generate a new, improved reasoning trace in a <think> block.
    - The new reasoning should be more logical, clear, and directly lead to a plausible answer for the given question.
    - Address the flaws you identified. Assume you are looking at a typical indoor scene where the chair is in front of the bookshelf.

**Output Format:**
<critique>
[Your detailed critique here]
</critique>
<think>
[Your new, improved reasoning here]
</think>
"""

def run_evaluation_and_refinement(vqa_pair: dict):
    """
    Takes a VQA pair, uses an LLM to critique and refine the reasoning.
    """
    print("----- ORIGINAL VQA PAIR -----")
    print(json.dumps(vqa_pair, indent=2))

    prompt = EVALUATION_PROMPT_TEMPLATE.format(
        question=vqa_pair["question"],
        reasoning=vqa_pair["reasoning"]
    )

    try:
        response = client.chat.completions.create(
            model="gpt-4-turbo-preview",
            messages=[
                {"role": "system", "content": "You are an expert in spatial reasoning and logical evaluation."},
                {"role": "user", "content": prompt}
            ],
            temperature=0.2,
        )
        refined_output = response.choices[0].message.content
        print("\n----- EVALUATION AND REFINEMENT -----")
        print(refined_output)

        # You can further parse the output to separate critique and new reasoning
        if '<critique>' in refined_output and '<think>' in refined_output:
            critique = refined_output.split('<critique>')[1].split('</critique>')[0].strip()
            new_reasoning = refined_output.split('<think>')[1].split('</think>')[0].strip()

            print("\n----- PARSED REFINED REASONING -----")
            print(f"<think>\n{new_reasoning}\n</think>")
        else:
            print("\n----- COULD NOT PARSE REFINEMENT OUTPUT -----")

    except Exception as e:
        print(f"\nAn error occurred: {e}")
        print("Please ensure your OPENAI_API_KEY is set correctly.")

if __name__ == "__main__":
    run_evaluation_and_refinement(SAMPLE_VQA_PAIR)
